arguments.new_str:
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex removed: Cosmos DB indexes are managed via the container's indexing policy,
    // not EF Core. EF Core 9 throws instead of silently ignoring HasIndex.

    // Preserve the old discriminator property name ("Discriminator" instead of new default "$type")
    // so existing documents remain queryable.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // Preserve the old compound id format ("Blog|1") so existing documents remain accessible.
    // EF Core 9 defaults to key-only ids (e.g. "1").
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);
}

